public interface IFileNode {
  int Size();
}

public class FileLeaf : IFileNode {
  private readonly int _size;
  public FileLeaf(int size) { _size = size; }
  public int Size() => _size;
}

public class FolderComposite : IFileNode {
  private readonly List<IFileNode> _children = new List<IFileNode>();
  public void Add(IFileNode node) => _children.Add(node);
  public int Size() => _children.Sum(child => child.Size());
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Composite_ComputesTotalSizeRecursively() {
  var folder = new FolderComposite();
  folder.Add(new FileLeaf(10));
  folder.Add(new FileLeaf(20));
  Assert.AreEqual(30, folder.Size());
}

[TestMethod]
public void Leaf_AndCompositeShareSameInterface() {
  IFileNode leaf = new FileLeaf(5);
  IFileNode composite = new FolderComposite();
  Assert.AreEqual(5, leaf.Size());
  Assert.AreEqual(0, composite.Size());
}
